window.__p5Ready = new Promise((resolve, reject) => {
  if (window.p5) {
    resolve(window.p5);
    return;
  }

  const script = document.createElement("script");
  script.src = "https://cdn.jsdelivr.net/npm/p5@1.9.4/lib/p5.min.js";
  script.onload = () => resolve(window.p5);
  script.onerror = () => reject(new Error("No se pudo cargar p5.js"));
  document.head.appendChild(script);
});
